package main; import ("log"; "os"; "bountyvault/internal/database"; "github.com/joho/godotenv"); func main() { godotenv.Load("../.env"); dbURL := os.Getenv("DATABASE_URL"); database.Connect(dbURL); var c int; database.DB.QueryRow("SELECT COUNT(*) FROM disputes").Scan(&c); log.Printf("Count: %d", c); var did string; err := database.DB.QueryRow("SELECT id::text FROM disputes LIMIT 1").Scan(&did); if err != nil { log.Fatal(err) }; var b string; err = database.DB.QueryRow("SELECT COALESCE(pc.username, 'Unknown') FROM disputes d LEFT JOIN profiles pc ON d.creator_id = pc.id WHERE d.id::text = $1 OR d.dispute_id = $1", did).Scan(&b); log.Printf("Query %s: %v, %v", did, b, err) }
